import React, { useEffect, useState } from "react";

function Orders() {
  const [foods, setFoods] = useState([]);
  const [orders, setOrders] = useState([]);
  const [foodName, setFoodName] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [message, setMessage] = useState("");

  const loadFoods = () => {
    fetch("http://localhost:8080/foods")
      .then((res) => res.json())
      .then((data) => setFoods(data))
      .catch((err) => console.error(err));
  };

  const loadOrders = () => {
    fetch("http://localhost:8080/orders")
      .then((res) => res.json())
      .then((data) => setOrders(data))
      .catch((err) => console.error(err));
  };

  useEffect(() => {
    loadFoods();
    loadOrders();
  }, []);

  const placeOrder = async () => {
    const selectedFood = foods.find((food) => food.name === foodName);

    if (!selectedFood) {
      setMessage("Please select a valid food item");
      return;
    }

    const orderData = {
      foodName: foodName,
      quantity: Number(quantity),
      totalPrice: selectedFood.price * Number(quantity),
      status: "Pending",
    };

    try {
      const response = await fetch("http://localhost:8080/orders", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(orderData),
      });

      if (!response.ok) {
        throw new Error("Failed to place order");
      }

      setMessage("Order placed successfully");
      setFoodName("");
      setQuantity(1);
      loadOrders();
    } catch (error) {
      console.error(error);
      setMessage("Could not connect to backend");
    }
  };

  const updateOrderStatus = async (order, newStatus) => {
    try {
      const response = await fetch(`http://localhost:8080/orders/${order.id}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          foodName: order.foodName,
          quantity: order.quantity,
          totalPrice: order.totalPrice,
          status: newStatus,
        }),
      });

      if (!response.ok) {
        throw new Error("Failed to update order");
      }

      setMessage("Order status updated");
      loadOrders();
    } catch (error) {
      console.error(error);
      setMessage("Could not update order");
    }
  };

  return (
    <div>
      <h2>Place Order</h2>

      <select value={foodName} onChange={(e) => setFoodName(e.target.value)}>
        <option value="">Select Food</option>
        {foods.map((food) => (
          <option key={food.id} value={food.name}>
            {food.name} - ₹{food.price}
          </option>
        ))}
      </select>

      <br /><br />

      <input
        type="number"
        min="1"
        value={quantity}
        onChange={(e) => setQuantity(e.target.value)}
      />

      <br /><br />

      <button onClick={placeOrder}>Place Order</button>

      {message && <p>{message}</p>}

      <hr />

      <h2>Order Status</h2>

      {orders.length === 0 ? (
        <p>No orders yet.</p>
      ) : (
        orders.map((order) => (
          <div
            key={order.id}
            style={{
              marginBottom: "10px",
              padding: "10px",
              border: "1px solid #ccc",
              borderRadius: "8px",
              width: "400px"
            }}
          >
            <strong>{order.foodName}</strong><br />
            Quantity: {order.quantity}<br />
            Total: ₹{order.totalPrice}<br />
            Status: {order.status}
            <br /><br />
            <button onClick={() => updateOrderStatus(order, "Pending")}>
              Pending
            </button>
            <button
              onClick={() => updateOrderStatus(order, "Completed")}
              style={{ marginLeft: "10px" }}
            >
              Completed
            </button>
            <button
              onClick={() => updateOrderStatus(order, "Cancelled")}
              style={{ marginLeft: "10px" }}
            >
              Cancelled
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default Orders;
